import workflow, time

def mock(tool, args):
    if tool == "fail":
        return "[error] boom"
    return f"ok_{tool}"

nodes = [
    {"id": "A", "tool": "fail", "args": {}},
    {"id": "B", "tool": "process", "args": {}, "deps": ["A"]},
    {"id": "C", "tool": "process", "args": {}, "deps": ["A"]},
    {"id": "D", "tool": "cleanup", "args": {}, "deps": ["B", "C"], "skip_on_dep_fail": False},
]

# Patch to add debug
import workflow as wf
original_execute = wf.execute

def debug_execute(nodes, dispatch_fn, max_workers=4):
    # Inline copy with debug
    t0 = time.time()
    order, err = wf._topo_sort(nodes)
    if err:
        return {"results": {}, "errors": {"_": err}, "skipped": [], "order": [], "elapsed": 0.0}

    node_map = {n["id"]: n for n in nodes}
    results = {}
    errors = {}
    skipped = set()
    completed = set()
    remaining = set(order)
    wave = 0

    while remaining:
        wave += 1
        ready = []
        to_skip = []
        print(f"\n--- Wave {wave} ---")
        print(f"  remaining: {remaining}")
        print(f"  completed: {completed}")
        print(f"  errors: {set(errors.keys())}")
        print(f"  skipped: {skipped}")

        for nid in list(remaining):
            node = node_map[nid]
            deps = node.get("deps", [])

            dep_failed = any(dep in errors for dep in deps)
            dep_skipped = any(dep in skipped for dep in deps)

            skip_on_fail = node.get("skip_on_dep_fail", True)

            if (dep_failed or dep_skipped) and skip_on_fail:
                to_skip.append(nid)
                print(f"  {nid}: SKIP (dep_failed={dep_failed}, dep_skipped={dep_skipped})")
                continue

            if dep_failed or dep_skipped:
                deps_resolved = all(dep in completed or dep in errors or dep in skipped for dep in deps)
                print(f"  {nid}: no-skip, deps_resolved={deps_resolved}, deps={deps}")
                if deps_resolved:
                    ready.append(nid)
                continue

            if all(dep in completed for dep in deps):
                ready.append(nid)
                print(f"  {nid}: READY")
            else:
                print(f"  {nid}: waiting (deps not completed)")

        for nid in to_skip:
            skipped.add(nid)
            remaining.discard(nid)

        if not ready:
            for nid in list(remaining):
                if nid not in skipped:
                    skipped.add(nid)
                remaining.discard(nid)
            break

        remaining -= set(ready)

        def _exec_node(nid):
            node = node_map[nid]
            tool = node.get("tool", "")
            args = dict(node.get("args", {}))
            try:
                result = dispatch_fn(tool, args)
                if isinstance(result, str) and result.startswith("[error]"):
                    return nid, None, result
                return nid, result, None
            except Exception as e:
                return nid, None, f"[error] {e}"

        import concurrent.futures
        with concurrent.futures.ThreadPoolExecutor(max_workers=min(max_workers, len(ready))) as executor:
            futures = {executor.submit(_exec_node, nid): nid for nid in ready}
            for future in concurrent.futures.as_completed(futures):
                nid, result, error = future.result()
                if error:
                    errors[nid] = error
                else:
                    results[nid] = result
                completed.add(nid)

        print(f"  executed: {ready}")

    return {"results": results, "errors": errors, "skipped": list(skipped), "order": order, "elapsed": round(time.time()-t0, 2)}

result = debug_execute(nodes, mock)
print(f"\nFinal: results={list(result['results'].keys())}, errors={list(result['errors'].keys())}, skipped={result['skipped']}")
